# nfrs/throughput_calculator.py
from dataclasses import dataclass
import math

@dataclass
class ThroughputNFR:
    peak_concurrent_users: int
    avg_requests_per_user_per_minute: float
    avg_input_tokens_per_request: int
    avg_output_tokens_per_request: int

    @property
    def peak_rps(self) -> float:
        return (self.peak_concurrent_users * self.avg_requests_per_user_per_minute) / 60

    @property
    def peak_input_tpm(self) -> int:
        return int(self.peak_rps * 60 * self.avg_input_tokens_per_request)

    @property
    def peak_output_tpm(self) -> int:
        return int(self.peak_rps * 60 * self.avg_output_tokens_per_request)

    @property
    def peak_total_tpm(self) -> int:
        return self.peak_input_tpm + self.peak_output_tpm

    def required_api_tier_tpm(self, safety_factor: float = 1.3) -> int:
        # Apply safety factor: provision 30% above peak to handle bursts
        return math.ceil(self.peak_total_tpm * safety_factor)

# Example: 500 concurrent users, 4 requests/minute, 2000 input + 400 output tokens
nfr = ThroughputNFR(
    peak_concurrent_users=500,
    avg_requests_per_user_per_minute=4.0,
    avg_input_tokens_per_request=2000,
    avg_output_tokens_per_request=400,
)
print(f"Peak rps: {nfr.peak_rps:.1f}")              # 33.3 rps
print(f"Required API tier TPM: {nfr.required_api_tier_tpm():,}")  # 3,004,000 TPM

# rate_limit_monitor.py
import anthropic
from dataclasses import dataclass
import logging

@dataclass
class RateLimitState:
    remaining_requests: int
    limit_requests: int
    remaining_tokens: int
    limit_tokens: int

    @property
    def request_headroom_pct(self) -> float:
        return (self.remaining_requests / self.limit_requests) * 100

    @property
    def token_headroom_pct(self) -> float:
        return (self.remaining_tokens / self.limit_tokens) * 100

def extract_rate_limit_state(response: anthropic.types.Message) -> RateLimitState:
    # Rate limit headers are in response.model_fields_set or via response._response.headers
    headers = response._request_id  # implementation detail — access via httpx response
    return RateLimitState(
        remaining_requests=int(headers.get("x-ratelimit-remaining-requests", 0)),
        limit_requests=int(headers.get("x-ratelimit-limit-requests", 1)),
        remaining_tokens=int(headers.get("x-ratelimit-remaining-tokens", 0)),
        limit_tokens=int(headers.get("x-ratelimit-limit-tokens", 1)),
    )

def check_and_alert(state: RateLimitState, alert_threshold_pct: float = 20.0) -> None:
    if state.request_headroom_pct < alert_threshold_pct:
        logging.warning(
            "Rate limit headroom low: %.1f%% requests remaining",
            state.request_headroom_pct,
        )
    if state.token_headroom_pct < alert_threshold_pct:
        logging.warning(
            "Rate limit headroom low: %.1f%% tokens remaining",
            state.token_headroom_pct,
        )

# degradation/level_manager.py
from enum import IntEnum
from dataclasses import dataclass

class DegradationLevel(IntEnum):
    FULL_SERVICE = 0
    REDUCED_CONTEXT = 1
    NO_RETRIEVAL = 2
    CACHED_RESPONSES = 3
    STATIC_FALLBACK = 4

@dataclass
class DegradationState:
    level: DegradationLevel = DegradationLevel.FULL_SERVICE

    def max_retrieved_chunks(self) -> int:
        return {
            DegradationLevel.FULL_SERVICE: 8,
            DegradationLevel.REDUCED_CONTEXT: 4,
            DegradationLevel.NO_RETRIEVAL: 0,
            DegradationLevel.CACHED_RESPONSES: 0,
            DegradationLevel.STATIC_FALLBACK: 0,
        }[self.level]

    def use_live_model(self) -> bool:
        return self.level < DegradationLevel.CACHED_RESPONSES

def evaluate_degradation_level(
    retrieval_p95_ms: float,
    claude_api_p95_ms: float,
    circuit_open_seconds: float,
) -> DegradationLevel:
    if circuit_open_seconds > 60:
        return DegradationLevel.STATIC_FALLBACK
    if claude_api_p95_ms > 5000:
        return DegradationLevel.CACHED_RESPONSES
    if retrieval_p95_ms > 2000:
        return DegradationLevel.NO_RETRIEVAL
    if retrieval_p95_ms > 800:
        return DegradationLevel.REDUCED_CONTEXT
    return DegradationLevel.FULL_SERVICE

# metrics/nfr_reporter.py
import time
from prometheus_client import Histogram, Counter

REQUEST_LATENCY = Histogram(
    "claude_request_latency_seconds",
    "End-to-end request latency",
    ["deployment_id", "model", "outcome"],
    buckets=[0.1, 0.25, 0.5, 0.75, 1.0, 1.5, 2.0, 3.0, 5.0, 10.0],
)

COMPONENT_LATENCY = Histogram(
    "claude_component_latency_seconds",
    "Per-component latency",
    ["deployment_id", "component"],
    buckets=[0.05, 0.1, 0.25, 0.5, 0.75, 1.0, 2.0, 5.0],
)

REQUESTS_TOTAL = Counter(
    "claude_requests_total",
    "Total request count",
    ["deployment_id", "outcome"],
)

TOKENS_TOTAL = Counter(
    "claude_tokens_total",
    "Total token count",
    ["deployment_id", "token_type"],  # input or output
)

class NFRTimer:
    def __init__(self, deployment_id: str):
        self.deployment_id = deployment_id
        self._timings: dict[str, float] = {}

    def record(self, component: str) -> "ComponentTimer":
        return ComponentTimer(self, component)

    def emit(self, model: str, outcome: str, input_tokens: int, output_tokens: int):
        total = sum(self._timings.values())
        REQUEST_LATENCY.labels(self.deployment_id, model, outcome).observe(total)
        for component, duration in self._timings.items():
            COMPONENT_LATENCY.labels(self.deployment_id, component).observe(duration)
        REQUESTS_TOTAL.labels(self.deployment_id, outcome).inc()
        TOKENS_TOTAL.labels(self.deployment_id, "input").inc(input_tokens)
        TOKENS_TOTAL.labels(self.deployment_id, "output").inc(output_tokens)

class ComponentTimer:
    def __init__(self, nfr_timer: NFRTimer, component: str):
        self.nfr_timer = nfr_timer
        self.component = component

    def __enter__(self):
        self._start = time.monotonic()
        return self

    def __exit__(self, *args):
        self.nfr_timer._timings[self.component] = time.monotonic() - self._start
